from functools import lru_cache
@lru_cache(maxsize=None)
def T(n: int, k: int) -> int:
    if n == 1: return 1
    if k == 0: return n * T(n - 1, 0)
    numer = (n ** k) * (n - 1) * T(n - 1, k - 1)
    denom = ((n - 1) ** (k - 1)) * k
    return numer // denom
for n in range(1, 8): print([T(n, k) for k in range(n)]) # _Peter Luschny_, Mar 05 2026

